import{initMatrix}from '../core/matrix.js';import{initCursor,initScrollbar}from '../core/ui.js';const ALL_FIELDS=["businessGoal","audience","projectType","sections","content","media","uiux","palette","fonts","inspirations","cta","seo","constraints",];const FIELD_LABELS={businessGoal:"Cel biznesowy",audience:"Grupa docelowa",projectType:"Typ projektu",sections:"Sekcje/funkcje",content:"Treści",media:"Media",uiux:"Styl UI/UX",palette:"Paleta",fonts:"Fonty",inspirations:"Inspiracje",cta:"CTA",seo:"SEO",constraints:"Ograniczenia",};const VALIDATION_MESSAGES={businessGoal:{required:"Opisz cel biznesowy swojego projektu.",min:(n)=>"Opis celu jest zbyt krótki "+"(min. "+n+" znaków)."},audience:{required:"Zdefiniuj grupę docelową "+"(Twoich klientów).",min:(n)=>"Opis grupy jest zbyt krótki "+"(min. "+n+" znaków)."},default:{required:"To pole jest wymagane.",min:(n)=>"Wymagane jest minimum "+n+" znaków."}};let briefToken=null;let briefSig=null;let turnstileToken=null;let turnstileWidgetId=null;let turnstileRenderPromise=null;let demoMode=false;let preloaderAnimId=null;let preloaderResizeCleanup=null;const TURNSTILE_API_TIMEOUT_MS=10000;function initPreloaderMatrix(){const canvas=document.getElementById("preloader-matrix");if(!canvas)return;const ctx=canvas.getContext("2d");let width=(canvas.width=window.innerWidth);let height=(canvas.height=window.innerHeight);const cols=Math.floor(width/20);const ypos=Array(cols).fill(0);let lastTime=0;const fps=15;let interval=1000/fps;let frameCount=0;const fastLoadFrames=60;const fastFPS=30;const resizeHandler=()=>{width=canvas.width=window.innerWidth;height=canvas.height=window.innerHeight;};window.addEventListener("resize",resizeHandler,{passive:true});preloaderResizeCleanup=()=>{window.removeEventListener("resize",resizeHandler);};function matrixLoop(currentTime){preloaderAnimId=requestAnimationFrame(matrixLoop);if(!currentTime)currentTime=0;if(frameCount<fastLoadFrames){interval=1000/fastFPS;frameCount++;}else{interval=1000/fps;}const delta=currentTime-lastTime;if(delta<interval)return;lastTime=currentTime-(delta%interval);ctx.fillStyle="rgba(5,5,5,0.08)";ctx.fillRect(0,0,width,height);ctx.font="15pt monospace";ypos.forEach((y,ind)=>{const chars="01DOMINDEVBRIEFXYZ";const text=chars[Math.floor(Math.random()*chars.length)];const x=ind*20;ctx.fillStyle=Math.random()>0.98?"#fff":"#ff1f1f";ctx.fillText(text,x,y);if(y>100+Math.random()*10000){ypos[ind]=0;}else{ypos[ind]=y+20;}});}requestAnimationFrame(matrixLoop);}const killPreloader=()=>{const preloader=document.getElementById("preloader");if(!preloader)return;if(preloader.classList.contains("hiding"))return;preloader.classList.add("hiding");preloader.classList.add("loaded");setTimeout(()=>{preloader.style.display="none";document.body.style.overflow='';if(preloaderAnimId){cancelAnimationFrame(preloaderAnimId);preloaderAnimId=null;}if(preloaderResizeCleanup){preloaderResizeCleanup();preloaderResizeCleanup=null;}initMatrix();initCursor();},550);};function setSubmitEnabled(isEnabled){const submitBtn=document.getElementById("btn-submit");if(!submitBtn||demoMode)return;submitBtn.disabled=!isEnabled;}function setTurnstileStatus(message,state=""){const statusEl=document.getElementById("turnstile-status");if(!statusEl)return;statusEl.textContent=message;if(state){statusEl.dataset.state=state;}else{delete statusEl.dataset.state;}}function handleTurnstileSuccess(token){turnstileToken=token;setSubmitEnabled(true);setTurnstileStatus("Weryfikacja potwierdzona. Możesz wysłać brief.","success");}function resetTurnstileState(message="Potwierdź weryfikację bezpieczeństwa,aby odblokować wysyłkę.",state="idle"){turnstileToken=null;setSubmitEnabled(false);setTurnstileStatus(message,state);}function waitForTurnstileApi(timeoutMs=TURNSTILE_API_TIMEOUT_MS){return new Promise((resolve,reject)=>{if(window.turnstile?.render){resolve(window.turnstile);return;}const startedAt=Date.now();const poll=window.setInterval(()=>{if(window.turnstile?.render){window.clearInterval(poll);resolve(window.turnstile);return;}if(Date.now()-startedAt>=timeoutMs){window.clearInterval(poll);reject(new Error("Turnstile API load timed out."));}},50);});}function ensureTurnstileRendered({reset=false}={}){if(demoMode)return Promise.resolve();const container=document.getElementById("brief-turnstile");if(!container)return Promise.resolve();if(turnstileWidgetId!==null&&window.turnstile?.reset){if(reset){window.turnstile.reset(turnstileWidgetId);resetTurnstileState("Potwierdź weryfikację bezpieczeństwa ponownie,aby wysłać brief.");}return Promise.resolve(turnstileWidgetId);}if(turnstileRenderPromise)return turnstileRenderPromise;resetTurnstileState("Ładuję weryfikację bezpieczeństwa...","loading");turnstileRenderPromise=waitForTurnstileApi().then((turnstile)=>{if(turnstileWidgetId!==null)return turnstileWidgetId;turnstileWidgetId=turnstile.render(container,{sitekey:container.dataset.sitekey,theme:container.dataset.theme||"auto",language:container.dataset.language||"auto",callback:handleTurnstileSuccess,"expired-callback":()=>{resetTurnstileState("Weryfikacja wygasła. Potwierdź ją ponownie.");},"error-callback":()=>{resetTurnstileState("Nie udało się załadować weryfikacji. Odśwież stronę lub spróbuj ponownie.","error");},});setTurnstileStatus("Potwierdź weryfikację bezpieczeństwa,aby odblokować wysyłkę.","idle");return turnstileWidgetId;}).catch((error)=>{console.error("Failed to initialize Turnstile:",error);resetTurnstileState("Nie udało się załadować weryfikacji. Odśwież stronę lub spróbuj ponownie.","error");return null;}).finally(()=>{turnstileRenderPromise=null;});return turnstileRenderPromise;}document.addEventListener("DOMContentLoaded",()=>{initPreloaderMatrix();initBriefApp();initScrollbar();});async function initBriefApp(){const params=new URLSearchParams(window.location.search);if(params.get("demo")==="1"){demoMode=true;briefToken="demo";briefSig="demo";const emailEl=document.getElementById("brief-email");if(emailEl)emailEl.textContent="demo@example.com";const submitBtn=document.getElementById("btn-submit");if(submitBtn)submitBtn.disabled=false;showState("form");setupStepNavigation();setupAutosave();setupSubmit();setupClearDraft();setupRetry();setupHints();setTimeout(killPreloader,500);return;}briefToken=params.get("t");briefSig=params.get("sig");if(!briefToken||!briefSig){showState("expired");setTimeout(killPreloader,500);return;}showState("loading");try{const res=await fetch(`/api/brief-meta?t=${encodeURIComponent(briefToken)}&sig=${encodeURIComponent(briefSig)}`);const data=await res.json();if(!data.ok){if(data.errorCode==="TOKEN_USED"){showState("used");}else{showState("expired");}setTimeout(killPreloader,500);return;}const emailEl=document.getElementById("brief-email");if(emailEl)emailEl.textContent=data.email;restoreDraft();showState("form");setTimeout(killPreloader,800);}catch(err){console.error("Failed to load brief:",err);showState("expired");setTimeout(killPreloader,500);}setupStepNavigation();setupAutosave();setupSubmit();setupClearDraft();setupRetry();setupHints();}function showState(name){document.querySelectorAll(".brief-state").forEach((el)=>{el.hidden=el.id!==`state-${name}`;});if(name==="form"&&getCurrentStep()===5){ensureTurnstileRendered();}}function setupHints(){document.querySelectorAll('.hint-trigger').forEach(btn=>{btn.addEventListener('click',(e)=>{e.preventDefault();e.stopPropagation();const content=btn.nextElementSibling;const isActive=content.classList.contains('active');document.querySelectorAll('.hint-content.active').forEach(h=>h.classList.remove('active'));document.querySelectorAll('.hint-trigger.active').forEach(b=>b.classList.remove('active'));if(!isActive){content.classList.add('active');btn.classList.add('active');}});});document.addEventListener('click',(e)=>{if(!e.target.closest('.hint-content')){document.querySelectorAll('.hint-content.active').forEach(h=>h.classList.remove('active'));document.querySelectorAll('.hint-trigger.active').forEach(b=>b.classList.remove('active'));}});}function setupStepNavigation(){document.querySelectorAll(".step-tab").forEach((tab)=>{tab.addEventListener("click",()=>{const target=parseInt(tab.dataset.step);const current=getCurrentStep();if(target>current&&!validateStep(current))return;goToStep(target);});});document.querySelectorAll("[data-goto]").forEach((btn)=>{btn.addEventListener("click",()=>{const target=parseInt(btn.dataset.goto);const current=getCurrentStep();if(target>current&&!validateStep(current))return;goToStep(target);});});}function goToStep(step){document.querySelectorAll(".step-tab").forEach((tab)=>{const isActive=parseInt(tab.dataset.step)===step;tab.classList.toggle("active",isActive);tab.setAttribute("aria-selected",isActive);});document.querySelectorAll(".step-panel").forEach((panel)=>{const panelStep=parseInt(panel.id.replace("panel-",""));panel.hidden=panelStep!==step;panel.classList.toggle("active",panelStep===step);});const panel=document.getElementById(`panel-${step}`);const firstInput=panel.querySelector("input,textarea,select");if(firstInput)firstInput.focus();if(step===5){buildSummary();ensureTurnstileRendered();}const container=document.querySelector('.brief-container');if(container)container.scrollIntoView({behavior:'smooth',block:'start'});}function getCurrentStep(){const active=document.querySelector(".step-tab.active");return active?parseInt(active.dataset.step):1;}function validateStep(step){const panel=document.getElementById(`panel-${step}`);const fields=panel.querySelectorAll("[required]");let valid=true;fields.forEach((field)=>{const msgContainer=field.closest(".form-group").querySelector(".validation-msg");const minLen=parseInt(field.getAttribute("minlength")||"0");const value=field.value.trim();const fieldName=field.name;let error="";if(!value){error=(VALIDATION_MESSAGES[fieldName]?.required)||VALIDATION_MESSAGES.default.required;}else if(value.length<minLen){error=(VALIDATION_MESSAGES[fieldName]?.min?.(minLen))||VALIDATION_MESSAGES.default.min(minLen);}if(error){field.classList.add("invalid");field.setAttribute("aria-invalid","true");if(msgContainer){msgContainer.textContent=error;msgContainer.classList.add("visible");}valid=false;}else{field.classList.remove("invalid");field.removeAttribute("aria-invalid");if(msgContainer){msgContainer.textContent="";msgContainer.classList.remove("visible");}}});return valid;}const DRAFT_KEY=()=>`briefDraft:${briefToken}`;const DRAFT_TTL_MS=24*60*60*1000;function setupAutosave(){let timeout;const form=document.getElementById("brief-form");if(!form)return;form.addEventListener("input",(e)=>{if(e.target.classList.contains("invalid")){e.target.classList.remove("invalid");const msg=e.target.closest(".form-group").querySelector(".validation-msg");if(msg)msg.classList.remove("visible");}clearTimeout(timeout);timeout=setTimeout(saveDraft,500);});}function saveDraft(){if(!briefToken)return;const data=collectAnswers();const record={data,savedAt:Date.now()};try{localStorage.setItem(DRAFT_KEY(),JSON.stringify(record));}catch{}}function restoreDraft(){if(!briefToken)return;try{const raw=localStorage.getItem(DRAFT_KEY());if(!raw)return;const{data,savedAt}=JSON.parse(raw);if(Date.now()-savedAt>DRAFT_TTL_MS){localStorage.removeItem(DRAFT_KEY());return;}ALL_FIELDS.forEach((key)=>{const el=document.querySelector(`[name="${key}"]`);if(el&&data[key])el.value=data[key];});}catch{}}function setupClearDraft(){const btn=document.getElementById("btn-clear-draft");if(!btn)return;btn.addEventListener("click",()=>{if(!briefToken)return;if(confirm("Czy na pewno chcesz usunąć zapisany szkic?")){localStorage.removeItem(DRAFT_KEY());ALL_FIELDS.forEach((key)=>{const el=document.querySelector(`[name="${key}"]`);if(el)el.value="";});goToStep(1);}});}function collectAnswers(){const answers={};ALL_FIELDS.forEach((key)=>{const el=document.querySelector(`[name="${key}"]`);answers[key]=el?el.value.trim():"";});return answers;}function buildSummary(){const answers=collectAnswers();const container=document.getElementById("brief-summary");if(!container)return;container.innerHTML=Object.entries(FIELD_LABELS).map(([key,label])=>{const val=answers[key]||"\u2014";const isRequired=["businessGoal","audience"].includes(key);return `<div class="summary-item"><dt>${escapeHtml(label)}${isRequired?"*":""}</dt><dd>${escapeHtml(val)}</dd></div>`;}).join("");}function escapeHtml(text){const div=document.createElement("div");div.textContent=text;return div.innerHTML;}function setupSubmit(){const form=document.getElementById("brief-form");if(!form)return;form.addEventListener("submit",async(e)=>{e.preventDefault();if(!validateStep(1)){goToStep(1);return;}if(!demoMode&&!turnstileToken){ensureTurnstileRendered();setTurnstileStatus("Potwierdz weryfikacje bezpieczenstwa aby wyslac brief.","idle");alert("Proszę potwierdzić weryfikację Turnstile.");return;}showState("submitting");if(demoMode){setTimeout(()=>showState("success"),800);return;}try{const res=await fetch("/api/brief-submit",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({t:briefToken,sig:briefSig,turnstileToken,answers:collectAnswers(),}),});const data=await res.json();if(data.ok){localStorage.removeItem(DRAFT_KEY());showState("success");}else if(data.errorCode==="TOKEN_USED"){showState("used");}else{const errorEl=document.getElementById("error-message");if(errorEl)errorEl.textContent=data.message||"Wystąpił błąd. Twoje odpowiedzi są zapisane — spróbuj ponownie.";showState("error");}}catch(err){console.error("Submit failed:",err);const errorEl=document.getElementById("error-message");if(errorEl)errorEl.textContent="Problem z połączeniem. Twoje odpowiedzi są zapisane — spróbuj ponownie.";showState("error");}});}function setupRetry(){const btn=document.getElementById("btn-retry");if(!btn)return;btn.addEventListener("click",()=>{showState("form");ensureTurnstileRendered({reset:true});});}